    const char *method = req->buffer;
    const char *path = strchr(method, ' ');
    if (!path) return;
    path++;
    
    const char *version = strchr(path, ' ');
    if (!version) return;
    version++;
    
    const char *end = strstr(version, "\r\n\r\n");
